import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read the entire line

        char[] buffer = new char[10];

        // Copy user input into buffer with length checking
        int length = Math.min(name.length(), buffer.length); // Limit input length to buffer size
        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
